document.addEventListener("DOMContentLoaded", function () {
    var sidebar = document.querySelector(".sidebar");
    if (sidebar) {
        var saved = sessionStorage.getItem("sidebar-scroll");
        if (saved) { sidebar.scrollTop = parseInt(saved, 10); }
        sidebar.addEventListener("scroll", function () {
            sessionStorage.setItem("sidebar-scroll", sidebar.scrollTop);
        });
    }
});

// Close dropdown when clicking outside
document.addEventListener("click", function (e) {
    var dropdowns = document.querySelectorAll(".topbar__dropdown");
    var buttons = document.querySelectorAll(".topbar__profile-btn");
    dropdowns.forEach(function (dropdown, i) {
        if (!dropdown.contains(e.target) && !buttons[i].contains(e.target)) {
            dropdown.classList.remove("topbar__dropdown--open");
        }
    });
});

// Toast notification system
window.showToast = function (event) {
    const container = document.getElementById("toast-container");
    if (!container) return;
    const data = event.detail.value;
    const message = data.message || data;
    const type = data.type || "info";
    const duration = data.duration || 4000;

    const toast = document.createElement("div");
    toast.className = "toast toast--" + type;
    toast.setAttribute("role", "alert");
    toast.innerHTML = "<span>" + message + "</span>";

    container.appendChild(toast);

    setTimeout(function () {
        toast.style.animation = "toast-out 0.3s ease forwards";
        setTimeout(function () { toast.remove(); }, 300);
    }, duration);
};

// Modal open/close helpers
window.openModal = function (modalId) {
    var modal = document.getElementById(modalId);
    if (modal) { modal.style.display = "flex"; }
};

window.closeModal = function (modalId) {
    var modal = document.getElementById(modalId);
    if (modal) { modal.remove(); }
};

// Close modal on overlay click
document.addEventListener("click", function (e) {
    if (e.target.classList.contains("modal-overlay")) {
        e.target.remove();
    }
});

// Close modal on Escape key
document.addEventListener("keydown", function (e) {
    if (e.key === "Escape") {
        var overlay = document.querySelector(".modal-overlay");
        if (overlay) { overlay.remove(); }
    }
});
